    modal.setAttribute('data-canopy-gallery-dismiss-bound', '1');
    modal.addEventListener('click', function (event) {
      if (!shouldCloseFromBackground(event, modal)) return;
      event.preventDefault();
      closeModalFromBackground(modal);
    });
